import React from 'react';
import { useNavigate } from 'react-router-dom';

const formatPrice = (price) => {
  if (!price && price !== 0) return 'N/A';
  return `$${Number(price).toLocaleString('en-AU')}/wk`;
};

const RentalCard = ({ rental }) => {
  const navigate = useNavigate();

  return (
    <article
      className="rental-card"
      onClick={() => navigate(`/rental/${rental.id}`)}
      role="button"
      tabIndex={0}
      onKeyDown={(e) => e.key === 'Enter' && navigate(`/rental/${rental.id}`)}
      aria-label={`View details for ${rental.address || 'rental property'}`}
    >
      <div className="rental-card__top">
        <span className="rental-card__badge">{rental.property_type || 'Property'}</span>
        <span className="rental-card__price-tag">{formatPrice(rental.price)}</span>
      </div>

      <div className="rental-card__body">
        <h3 className="rental-card__title">{rental.address || 'Address not available'}</h3>
        
        <div className="rental-card__location">
          <span className="location-text">{rental.suburb}, {rental.state}</span>
          <span className="location-zip">{rental.postcode}</span>
        </div>

        <div className="rental-card__amenities">
          {rental.bedrooms != null && (
            <div className="amenity-item">
              <span className="amenity-icon">🛌</span>
              <span className="amenity-label"><strong>{rental.bedrooms}</strong> Bed</span>
            </div>
          )}
          {rental.bathrooms != null && (
            <div className="amenity-item">
              <span className="amenity-icon">🚿</span>
              <span className="amenity-label"><strong>{rental.bathrooms}</strong> Bath</span>
            </div>
          )}
          {rental.parking_spaces != null && (
            <div className="amenity-item">
              <span className="amenity-icon">🚗</span>
              <span className="amenity-label"><strong>{rental.parking_spaces}</strong> Park</span>
            </div>
          )}
        </div>
      </div>
      
      <div className="rental-card__footer">
        <span className="view-link">View Listing →</span>
      </div>
    </article>
  );
};

export default RentalCard;
